115: fn test_repo(cargo: &Path, out_dir: &Path, test: &Test) {
116:     println!("testing {}", test.repo);
117:     let dir = clone_repo(test, out_dir);
118:     if let Some(lockfile) = test.lock {
119:         fs::write(&dir.join("Cargo.lock"), lockfile).unwrap();
120:     }
121:     if !run_cargo_test(cargo, &dir, test.packages, test.features, test.manifest_path, test.filters)
122:     {
123:         panic!("tests failed for {}", test.repo);
124:     }
125: }
126: 
127: fn clone_repo(test: &Test, out_dir: &Path) -> PathBuf {
128:     let out_dir = out_dir.join(test.name);
129: 
130:     if !out_dir.join(".git").is_dir() {
131:         let status = Command::new("git").arg("init").arg(&out_dir).status().unwrap();
132:         assert!(status.success());
133:     }
134: 
135:     // Try progressively deeper fetch depths to find the commit
136:     let mut found = false;
137:     for depth in &[0, 1, 10, 100, 1000, 100000] {
138:         if *depth > 0 {
139:             let status = Command::new("git")
140:                 .arg("fetch")
141:                 .arg(test.repo)
142:                 .arg(test.sha)
143:                 .arg(&format!("--depth={}", depth))
144:                 .current_dir(&out_dir)
145:                 .status()
146:                 .unwrap();
147:             assert!(status.success());
148:         }
149: 
150:         let status = Command::new("git")
151:             .arg("reset")
152:             .arg(test.sha)
153:             .arg("--hard")
154:             .current_dir(&out_dir)
155:             .status()
156:             .unwrap();
157: 
158:         if status.success() {
159:             found = true;
160:             break;
161:         }
162:     }
163: 
164:     if !found {
165:         panic!("unable to find commit {}", test.sha)
166:     }
167:     let status =
168:         Command::new("git").arg("clean").arg("-fdx").current_dir(&out_dir).status().unwrap();
169:     assert!(status.success());
170: 
171:     out_dir
172: }
173: 
174: fn run_cargo_test(
175:     cargo_path: &Path,
176:     crate_path: &Path,
177:     packages: &[&str],
178:     features: Option<&[&str]>,
179:     manifest_path: Option<&str>,
180:     filters: &[&str],
181: ) -> bool {
182:     let mut command = Command::new(cargo_path);
183:     command.arg("test");
184: 
185:     if let Some(path) = manifest_path {
186:         command.arg(format!("--manifest-path={}", path));
187:     }
188: 
189:     if let Some(features) = features {
190:         command.arg("--no-default-features");
191:         for feature in features {
192:             command.arg(format!("--features={}", feature));
193:         }
194:     }
195: 
196:     for name in packages {
197:         command.arg("-p").arg(name);
198:     }
199: 
200:     command.arg("--");
201:     command.args(filters);
202: 
203:     let status = command
204:         // Disable rust-lang/cargo's cross-compile tests
205:         .env("CFG_DISABLE_CROSS_TESTS", "1")
206:         // Relax #![deny(warnings)] in some crates
207:         .env("RUSTFLAGS", "--cap-lints warn")
208:         // servo tries to use 'lld-link.exe' on windows, but we don't
209:         // have lld on our PATH in CI. Override it to use 'link.exe'
210:         .env("CARGO_TARGET_X86_64_PC_WINDOWS_MSVC_LINKER", "link.exe")
211:         .env("CARGO_TARGET_I686_PC_WINDOWS_MSVC_LINKER", "link.exe")
212:         .current_dir(crate_path)
213:         .status()
214:         .unwrap();
215: 
216:     status.success()
217: }
